import { getOrderlyEnv, type OrderlyEnv } from "@/utils/environment";

function getOrderlyAppBaseUrl(env: OrderlyEnv) {
  return env === "prod"
    ? "https://app.orderly.network"
    : "https://staging-app.orderly.network";
}

export function getOrderlyAppLinks(env: OrderlyEnv = getOrderlyEnv()) {
  const baseUrl = getOrderlyAppBaseUrl(env);
  return {
    staking: `${baseUrl}/staking`,
    vaults: `${baseUrl}/vaults`,
    campaigns: `${baseUrl}/campaigns/?utm_source=orderly_one&utm_medium=navbar`,
  };
}
